const autocompleteSuggestions = $derived.by(() => {
    if (!isTagInputOpen || tagInputText.trim().length === 0) return [];
    const prefix = tagInputText.trim().toLowerCase();
    return tagInventory
      .filter((e) => e.name.includes(prefix))
      .sort((a, b) => b.usageCount - a.usageCount)
      .slice(0, 10);
  });
